DynamoDB batch operations can partially fail. Always handle `UnprocessedItems` with exponential backoff.

```typescript
import { DynamoDBDocumentClient, BatchWriteCommand } from '@aws-sdk/lib-dynamodb';
import { DynamoDBClient } from '@aws-sdk/client-dynamodb';

const client = DynamoDBDocumentClient.from(new DynamoDBClient({}));
const TABLE = process.env.TABLE_NAME!;

async function batchWrite(items: Record<string, any>[]) {
  // DynamoDB batch limit: 25 items
  const chunks = [];
  for (let i = 0; i < items.length; i += 25) {
    chunks.push(items.slice(i, i + 25));
  }

  for (const chunk of chunks) {
    let requestItems: Record<string, any> = {
      [TABLE]: chunk.map(item => ({
        PutRequest: { Item: item },
      })),
    };

    let retries = 0;
    const maxRetries = 5;

    while (Object.keys(requestItems).length > 0 && retries < maxRetries) {
      const result = await client.send(new BatchWriteCommand({
        RequestItems: requestItems,
      }));

      if (result.UnprocessedItems && Object.keys(result.UnprocessedItems).length > 0) {
        requestItems = result.UnprocessedItems;
        retries++;
        const delay = Math.pow(2, retries) * 100; // 200, 400, 800, 1600, 3200ms
        console.log(`Retrying ${Object.keys(requestItems).length} unprocessed items (attempt ${retries}, delay ${delay}ms)`);
        await new Promise(resolve => setTimeout(resolve, delay));
      } else {
        requestItems = {};
      }
    }

    if (Object.keys(requestItems).length > 0) {
      throw new Error(`Failed to write ${JSON.stringify(requestItems)} after ${maxRetries} retries`);
    }
  }
}

// Usage
await batchWrite([
  { pk: 'USER#1', sk: 'PROFILE', name: 'Alice' },
  { pk: 'USER#2', sk: 'PROFILE', name: 'Bob' },
  // ... up to any number of items
]);
```

`BatchWriteItem` has a 25-item limit per call. Unprocessed items occur due to throughput throttling. Exponential backoff prevents overwhelming the table during throttling events.

CDK apps should separate stack configuration per environment using context, environment variables, or a config file.

```typescript
// bin/app.ts
import * as cdk from 'aws-cdk-lib';
